INSERT INTO public.drupal_cache_discovery (cid, data, expire, created, serialized, tags, checksum) VALUES ('metatag_tags', 'a:89:{s:8:"abstract";a:13:{s:2:"id";s:8:"abstract";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:8:"Abstract";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:341:"A brief and concise summary of the page''s content, preferably 150 characters or less. Where as the description meta tag may be used by search engines to display a snippet about the page in search results, the abstract tag may be used to archive a summary about the page. This meta tag is <em>no longer</em> supported by major search engines.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:8:"abstract";s:5:"group";s:5:"basic";s:6:"weight";i:3;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:9:"trimmable";b:1;s:4:"long";b:1;s:5:"class";s:45:"Drupal\\metatag\\Plugin\\metatag\\Tag\\AbstractTag";s:8:"provider";s:7:"metatag";}s:6:"author";a:11:{s:2:"id";s:6:"author";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:6:"Author";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:28:"Define the author of a page.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:6:"author";s:5:"group";s:8:"advanced";s:6:"weight";i:4;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:40:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Author";s:8:"provider";s:7:"metatag";}s:13:"cache_control";a:11:{s:2:"id";s:13:"cache_control";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:13:"Cache control";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:140:"Used to control whether a browser caches a specific page locally. Not commonly used. Should be used in conjunction with the Pragma meta tag.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:13:"cache-control";s:5:"group";s:8:"advanced";s:6:"weight";i:10;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:46:"Drupal\\metatag\\Plugin\\metatag\\Tag\\CacheControl";s:8:"provider";s:7:"metatag";}s:13:"canonical_url";a:11:{s:2:"id";s:13:"canonical_url";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:13:"Canonical URL";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:140:"A link to the preferred page location or URL of the content of this page, to help eliminate duplicate content penalties from search engines.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:9:"canonical";s:5:"group";s:8:"advanced";s:6:"weight";i:1;s:4:"type";s:3:"uri";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:46:"Drupal\\metatag\\Plugin\\metatag\\Tag\\CanonicalUrl";s:8:"provider";s:7:"metatag";}s:11:"description";a:13:{s:2:"id";s:11:"description";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:11:"Description";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:206:"A brief and concise summary of the page''s content that is a maximum of 160 characters in length. The description meta tag may be used by search engines to display a snippet about the page in search results.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:11:"description";s:5:"group";s:5:"basic";s:6:"weight";i:2;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:4:"long";b:1;s:9:"trimmable";b:1;s:5:"class";s:45:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Description";s:8:"provider";s:7:"metatag";}s:7:"expires";a:11:{s:2:"id";s:7:"expires";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:7:"Expires";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:331:"Control when the browser''s internal cache of the current page should expire. The date must to be an <a href=''https://www.csgnetwork.com/timerfc1123calc.html''>RFC-1123</a>-compliant date string that is represented in Greenwich Mean Time (GMT), e.g. ''Thu, 01 Sep 2016 00:12:56 GMT''. Set to ''0'' to stop the page being cached entirely.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:7:"expires";s:5:"group";s:8:"advanced";s:6:"weight";i:11;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:41:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Expires";s:8:"provider";s:7:"metatag";}s:9:"generator";a:11:{s:2:"id";s:9:"generator";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:9:"Generator";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:97:"Describes the name and version number of the software or publishing tool used to create the page.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:9:"generator";s:5:"group";s:8:"advanced";s:6:"weight";i:4;s:4:"type";s:6:"string";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:43:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Generator";s:8:"provider";s:7:"metatag";}s:13:"geo_placename";a:11:{s:2:"id";s:13:"geo_placename";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:23:"Geographical place name";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:25:"A location''s formal name.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:13:"geo.placename";s:5:"group";s:8:"advanced";s:6:"weight";i:0;s:4:"type";s:5:"label";s:6:"secure";i:0;s:8:"multiple";b:0;s:5:"class";s:46:"Drupal\\metatag\\Plugin\\metatag\\Tag\\GeoPlacename";s:8:"provider";s:7:"metatag";}s:12:"geo_position";a:11:{s:2:"id";s:12:"geo_position";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:21:"Geographical position";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:261:"Geo-spatial information in ''latitude; longitude'' format, e.g. ''50.167958; -97.133185''; <a href=''https://en.wikipedia.org/wiki/Geographic_coordinate_system'' aria-label=''see Wikipedia for details on the geographic coordinate system''>see Wikipedia for details</a>.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:12:"geo.position";s:5:"group";s:8:"advanced";s:6:"weight";i:0;s:4:"type";s:5:"label";s:6:"secure";i:0;s:8:"multiple";b:0;s:5:"class";s:45:"Drupal\\metatag\\Plugin\\metatag\\Tag\\GeoPosition";s:8:"provider";s:7:"metatag";}s:10:"geo_region";a:11:{s:2:"id";s:10:"geo_region";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:19:"Geographical region";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:130:"A location''s two-letter international country code, with an optional two-letter region, e.g. ''US-NH'' for New Hampshire in the USA.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:10:"geo.region";s:5:"group";s:8:"advanced";s:6:"weight";i:0;s:4:"type";s:5:"label";s:6:"secure";i:0;s:8:"multiple";b:0;s:5:"class";s:43:"Drupal\\metatag\\Plugin\\metatag\\Tag\\GeoRegion";s:8:"provider";s:7:"metatag";}s:6:"google";a:11:{s:2:"id";s:6:"google";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:6:"Google";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:411:"This meta tag communicates with Google. There are currently two directives supported: ''nositelinkssearchbox'' to not to show the sitelinks search box, and ''notranslate'' to ask Google not to offer a translation of the page. Both options may be added, just separate them with a comma. See <a href=''https://support.google.com/webmasters/answer/79812?hl=en''>meta tags that Google understands</a> for further details.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:6:"google";s:5:"group";s:8:"advanced";s:6:"weight";i:5;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:40:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Google";s:8:"provider";s:7:"metatag";}s:4:"icbm";a:11:{s:2:"id";s:4:"icbm";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:4:"ICBM";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:227:"Geo-spatial information in ''latitude, longitude'' format, e.g. ''50.167958, -97.133185''; <a href=''https://en.wikipedia.org/wiki/ICBM_address'' aria-label=''see Wikipedia for details on ICBM addresses''>see Wikipedia for details</a>.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:4:"icbm";s:5:"group";s:8:"advanced";s:6:"weight";i:0;s:4:"type";s:5:"label";s:6:"secure";i:0;s:8:"multiple";b:0;s:5:"class";s:38:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Icbm";s:8:"provider";s:7:"metatag";}s:9:"image_src";a:11:{s:2:"id";s:9:"image_src";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:5:"Image";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:97:"An image associated with this page, for use as a thumbnail in social networks and other services.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:9:"image_src";s:5:"group";s:8:"advanced";s:6:"weight";i:4;s:4:"type";s:5:"image";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:42:"Drupal\\metatag\\Plugin\\metatag\\Tag\\ImageSrc";s:8:"provider";s:7:"metatag";}s:8:"keywords";a:11:{s:2:"id";s:8:"keywords";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:8:"Keywords";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:120:"A comma-separated list of keywords about the page. This meta tag is <em>no longer</em> supported by most search engines.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"name";s:8:"keywords";s:5:"group";s:5:"basic";s:6:"weight";i:4;s:4:"type";s:5:"label";s:6:"secure";b:0;s:8:"multiple";b:0;s:5:"class";s:42:"Drupal\\metatag\\Plugin\\metatag\\Tag\\Keywords";s:8:"provider";s:7:"metatag";}s:4:"next";a:11:{s:2:"id";s:4:"next";s:5:"label";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:13:"Next page URL";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:65:"Used for paginated content by providing URL with rel=''next'' link.";s:12:"\000*\000argument